enum ValidationDecision {
    case skip(reason: String)
    case validate(labels: [VisionClassifier.Label])
}

func gateForClaude(labels: [VisionClassifier.Label]) -> ValidationDecision {
    guard let top = labels.first, top.confidence >= 0.4 else {
        return .skip(reason: "Classification confidence too low to analyze")
    }
    // Filter to labels with confidence ≥ 0.45, cap at 6.
    let filtered = labels.filter { $0.confidence >= 0.45 }.prefix(6)
    return .validate(labels: Array(filtered))
}

struct ValidationResponse: Decodable {
    let valid: Bool
    let reason: String
    let advice: String?
}

actor VisionValidationService {
    private let session = URLSession.shared
    private let keychain = KeychainManager()
    private let keychainKey = "claude-api-key"

    func validate(labels: [VisionClassifier.Label],
                  question: String) async throws -> ValidationResponse {
        let topConfidence = labels.first?.confidence ?? 0
        let highConfidence = topConfidence >= 0.75

        let apiKey = try keychain.retrieve(key: keychainKey)

        var request = URLRequest(
            url: URL(string: "https://api.anthropic.com/v1/messages")!)
        request.httpMethod = "POST"
        request.setValue(apiKey, forHTTPHeaderField: "x-api-key")
        request.setValue("2023-06-01", forHTTPHeaderField: "anthropic-version")
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")

        let body: [String: Any] = [
            "model": "claude-haiku-4-5-20251001",  // fast + cheap for validation
            "max_tokens": 256,
            "system": ValidationPrompt.system,
            "messages": [
                ["role": "user",
                 "content": ValidationPrompt.user(
                     labels: labels,
                     question: question,
                     highConfidence: highConfidence)]
            ]
        ]
        request.httpBody = try JSONSerialization.data(withJSONObject: body)

        let (data, response) = try await session.data(for: request)
        guard let http = response as? HTTPURLResponse,
              http.statusCode == 200 else {
            throw URLError(.badServerResponse)
        }

        // Claude's response content is a JSON string — extract and decode it.
        let envelope = try JSONDecoder().decode(MessagesEnvelope.self, from: data)
        let text = envelope.content.first?.text ?? "{}"
        guard let jsonData = text.data(using: .utf8) else {
            throw DecodingError.dataCorrupted(.init(codingPath: [],
                debugDescription: "Not UTF-8"))
        }
        return try JSONDecoder().decode(ValidationResponse.self, from: jsonData)
    }
}

struct MessagesEnvelope: Decodable {
    struct Block: Decodable { let text: String }
    let content: [Block]
}

func stripMarkdownFences(_ text: String) -> String {
    var s = text.trimmingCharacters(in: .whitespacesAndNewlines)
    if s.hasPrefix("```") {
        // Remove opening fence line
        if let newline = s.firstIndex(of: "\n") {
            s = String(s[s.index(after: newline)...])
        }
        // Remove closing fence
        if s.hasSuffix("```") {
            s = String(s.dropLast(3))
        }
    }
    return s.trimmingCharacters(in: .whitespacesAndNewlines)
}

// Use before decoding:
let cleaned = stripMarkdownFences(text)
let jsonData = cleaned.data(using: .utf8) ?? Data()
return try JSONDecoder().decode(ValidationResponse.self, from: jsonData)

@MainActor
class ToiletAlarmViewModel: ObservableObject {
    @Published var result: ValidationResponse?
    @Published var statusMessage = ""
    @Published var isLoading = false

    private let classifier = VisionClassifier()
    private let validator = VisionValidationService()

    func analyze(image: UIImage, question: String) {
        isLoading = true
        statusMessage = "Classifying…"
        result = nil

        Task {
            defer { isLoading = false }
            do {
                // Step 1: on-device classification
                let labels = try await classifier.classify(
                    image: image, threshold: 0.3, maxResults: 10)

                // Step 2: confidence gate
                switch gateForClaude(labels: labels) {
                case .skip(let reason):
                    statusMessage = reason
                    return
                case .validate(let filtered):
                    statusMessage = "Asking Claude…"
                    // Step 3: send to Claude
                    result = try await validator.validate(
                        labels: filtered, question: question)
                    statusMessage = ""
                }
            } catch {
                statusMessage = "Error: \(error.localizedDescription)"
            }
        }
    }
}

enum ValidationError: LocalizedError {
    case keyNotFound
    case apiError(Int)
    case malformedResponse(String)

    var errorDescription: String? {
        switch self {
        case .keyNotFound:
            return "API key not configured. Add your Claude API key in Settings."
        case .apiError(let code):
            return "Claude returned status \(code). Check your API key."
        case .malformedResponse(let raw):
            return "Unexpected response format. Raw: \(raw.prefix(80))"
        }
    }
}

