protocol ValidationServiceProtocol {
    func validate(labels: [VisionClassifier.Label],
                  question: String) async throws -> ValidationResponse
}

extension VisionValidationService: ValidationServiceProtocol {}

struct StubValidationService: ValidationServiceProtocol {
    let response: ValidationResponse
    func validate(labels: [VisionClassifier.Label],
                  question: String) async throws -> ValidationResponse {
        response
    }
}

// XCTest
final class ToiletAlarmViewModelTests: XCTestCase {
    @MainActor func testValidResponseUpdatesResult() async {
        let expected = ValidationResponse(
            valid: true,
            reason: "Indoor cat scene.",
            advice: nil)
        let vm = ToiletAlarmViewModel(
            classifier: StubClassifier(labels: [
                .init(identifier: "cat", confidence: 0.92)]),
            validator: StubValidationService(response: expected))

        await vm.analyze(
            image: UIImage(), question: "Is this safe?")

        XCTAssertEqual(vm.result?.valid, true)
        XCTAssertEqual(vm.result?.reason, "Indoor cat scene.")
    }
}
